1	/**
2	 * LayerInfinite MCP Server — index.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * V2 Gateway Proxy entry point. Uses low-level Server (ADR-001)
5	 * for raw JSON-RPC interception of tools/list and tools/call.
6	 *
7	 * Registers handlers:
8	 *   tools/list   — enriched upstream tools + virtual li_recommend
9	 *   tools/call   — proxy to upstream, auto-mode rerouting
10	 *   resources/*  — gateway status + config (admin-gated)
11	 *   prompts/*    — setup instructions
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	import { Server } from '@modelcontextprotocol/sdk/server/index.js';
16	import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
17	import {
18	  CallToolRequestSchema,
19	  ListToolsRequestSchema,
20	} from '@modelcontextprotocol/sdk/types.js';
21	
22	import { loadConfig } from './config.js';
23	import type { GatewayConfig } from './config.js';
24	import { LiApiClient, UpstreamMCPClient } from './rest-client.js';
25	import { UpstreamRegistry } from './upstream-registry.js';
26	import { GatewayProxy } from './gateway-proxy.js';
27	import { logger } from './logger.js';
28	
29	const SERVER_NAME = 'layerinfinite-gateway';
30	const SERVER_VERSION = '2.0.0';
31	
32	const log = logger.forTool('index');
33	
34	// ── Task context extraction ─────────────────────────────────
35	
36	interface TaskContext {
37	  taskType: string;
38	  customerId: string;
39	  agentId: string;
40	}
41	
42	function extractTaskContext(params: Record<string, unknown> | undefined): TaskContext {
43	  const args = (params?.['arguments'] as Record<string, unknown>) ?? {};
44	  const meta = (params?.['_meta'] as Record<string, unknown>) ?? {};
45	
46	  const taskType = String(
47	    args['task_type'] ?? args['taskType'] ?? params?.['task_type'] ?? meta['taskType'] ?? 'unknown',
48	  );
49	
50	  const customerId = String(
51	    args['customer_id'] ??
52	      args['customerId'] ??
53	      params?.['customer_id'] ??
54	      process.env.LAYERINFINITE_DEFAULT_CUSTOMER ??
55	      'default',
56	  );
57	
58	  const agentId = String(
59	    meta['agentId'] ??
60	      args['agent_id'] ??
61	      args['agentId'] ??
62	      params?.['agent_id'] ??
63	      process.env.LAYERINFINITE_DEFAULT_AGENT ??
64	      'unknown',
65	  );
66	
67	  return { taskType, customerId, agentId };
68	}
69	
70	// ══════════════════════════════════════════════════════════════
71	// createGatewayServer
72	// ══════════════════════════════════════════════════════════════
73	
74	export interface GatewayServer {
75	  server: Server;
76	  proxy: GatewayProxy;
77	  config: GatewayConfig;
78	  upstreamClient: UpstreamMCPClient;
79	  registry: UpstreamRegistry;
80	}
81	
82	export function createGatewayServer(): GatewayServer {
83	  const config = loadConfig();
84	  const registry = new UpstreamRegistry(config);
85	  const liApi = new LiApiClient(config);
86	  const upstreamClient = new UpstreamMCPClient(registry);
87	  const proxy = new GatewayProxy(liApi, upstreamClient, registry, config);
88	
89	  const server = new Server(
90	    { name: SERVER_NAME, version: SERVER_VERSION },
91	    { capabilities: { tools: {}, resources: {}, prompts: {} } },
92	  );
93	
94	  const startedAt = Date.now();
95	
96	  // ── tools/list ──────────────────────────────────────────
97	
98	  server.setRequestHandler(ListToolsRequestSchema, async (request) => {
99	    try {
100	      const taskCtx = extractTaskContext(request.params as Record<string, unknown> | undefined);
101	      const enriched = await proxy.handleListTools(taskCtx);
102	
103	      // Strip internal fields (upstreamName, annotations) per MCP spec
104	      const tools = enriched.map((t) => ({
105	        name: t.name,
106	        description: t.description,
107	        inputSchema: t.inputSchema,
108	      }));
109	
110	      return { tools };
111	    } catch (err) {
112	      log.error('tools/list handler failed', {
113	        error: err instanceof Error ? err.message : String(err),
114	      });
115	      return { tools: [] };
116	    }
117	  });
118	
119	  // ── tools/call ──────────────────────────────────────────
120	
121	  server.setRequestHandler(CallToolRequestSchema, async (request) => {
122	    const toolName = request.params?.name ?? '';
123	    const args = (request.params?.arguments ?? {}) as Record<string, unknown>;
124	    const taskCtx = extractTaskContext(request.params as Record<string, unknown> | undefined);
125	
126	    try {
127	      const result = await proxy.handleCallTool(toolName, args, taskCtx);
128	      return result as unknown as { content: Array<{ type: string; text?: string }>; isError?: boolean };
129	    } catch (err) {
130	      const message = err instanceof Error ? err.message : String(err);
131	      log.error('tools/call handler failed', { tool: toolName, error: message });
132	      return {
133	        content: [{ type: 'text' as const, text: message }],
134	        isError: true,
135	      };
136	    }
137	  });
138	
139	  // ── resources/list ──────────────────────────────────────
140	
141	  server.setRequestHandler(
142	    { method: 'resources/list' } as never,
143	    async () => {
144	      try {
145	        const entries = registry.getAllUpstreams();
146	        const healthyCount = entries.filter((e) => registry.isHealthy(e.server.name)).length;
147	
148	        const resources = [
149	          {
150	            uri: 'li://gateway/status',
151	            name: 'Gateway Status',
152	            description: 'LayerInfinite Gateway Proxy runtime status',
153	            mimeType: 'text/plain',
154	          },
155	        ];
156	
157	        if (config.adminKey) {
158	          resources.push({
159	            uri: 'li://gateway/config',
160	            name: 'Gateway Configuration',
161	            description: 'Gateway config summary (requires admin key to read)',
162	            mimeType: 'application/json',
163	          });
164	        }
165	
166	        return { resources };
167	      } catch (err) {
168	        log.error('resources/list failed', { error: err instanceof Error ? err.message : String(err) });
169	        return { resources: [] };
170	      }
171	    },
172	  );
173	
174	  // ── resources/read ──────────────────────────────────────
175	
176	  server.setRequestHandler(
177	    { method: 'resources/read' } as never,
178	    async (request: { params?: { uri?: string } }) => {
179	      const uri = request.params?.uri ?? '';
180	
181	      try {
182	        if (uri === 'li://gateway/status') {
183	          const entries = registry.getAllUpstreams();
184	          const healthy = entries.filter((e) => registry.isHealthy(e.server.name));
185	          const uptimeMs = Date.now() - startedAt;
186	
187	          const status = {
188	            mode: config.mode ?? 'bootstrap',
189	            environment: config.environment,
190	            shadowMode: config.shadowMode,
191	            upstreams: {
192	              total: entries.length,
193	              healthy: healthy.length,
194	              names: entries.map((e) => e.server.name),
195	              healthyNames: healthy.map((e) => e.server.name),
196	            },
197	            uptime_seconds: Math.floor(uptimeMs / 1000),
198	            version: SERVER_VERSION,
199	          };
200	
201	          return {
202	            contents: [
203	              {
204	                uri,
205	                mimeType: 'text/plain',
206	                text: JSON.stringify(status, null, 2),
207	              },
208	            ],
209	          };
210	        }
211	
212	        if (uri === 'li://gateway/config') {
213	          return {
214	            contents: [
215	              {
216	                uri,
217	                mimeType: 'application/json',
218	                text: JSON.stringify(
219	                  {
220	                    mode: config.mode ?? 'bootstrap',
221	                    environment: config.environment,
222	                    shadowMode: config.shadowMode,
223	                    upstreamCount: config.upstreamServers.length,
224	                    modeOverrides: Object.fromEntries(config.modeOverrides),
225	                    apiKey: '[REDACTED]',
226	                    baseUrl: config.baseUrl,
227	                    adminEnabled: config.adminKey !== null,
228	                  },
229	                  null,
230	                  2,
231	                ),
232	              },
233	            ],
234	          };
235	        }
236	
237	        return {
238	          contents: [
239	            {
240	              uri,
241	              mimeType: 'text/plain',
242	              text: `Unknown resource: ${uri}`,
243	            },
244	          ],
245	        };
246	      } catch (err) {
247	        log.error('resources/read failed', { uri, error: err instanceof Error ? err.message : String(err) });
248	        return {
249	          contents: [{ uri, mimeType: 'text/plain', text: 'Error reading resource' }],
250	        };
251	      }
252	    },
253	  );
254	
255	  // ── prompts/list ────────────────────────────────────────
256	
257	  server.setRequestHandler(
258	    { method: 'prompts/list' } as never,
259	    async () => {
260	      return {
261	        prompts: [
262	          {
263	            name: 'layerinfinite-gateway-setup',
264	            description: 'LayerInfinite Gateway Proxy setup instructions',
265	            arguments: [],
266	          },
267	        ],
268	      };
269	    },
270	  );
271	
272	  // ── prompts/get ─────────────────────────────────────────
273	
274	  server.setRequestHandler(
275	    { method: 'prompts/get' } as never,
276	    async (request: { params?: { name?: string; arguments?: Record<string, unknown> } }) => {
277	      const name = request.params?.name ?? '';
278	
279	      if (name !== 'layerinfinite-gateway-setup') {
280	        return {
281	          messages: [
282	            {
283	              role: 'user' as const,
284	              content: { type: 'text' as const, text: `Unknown prompt: ${name}` },
285	            },
286	          ],
287	        };
288	      }
289	
290	      const text = [
291	        '# LayerInfinite Gateway Proxy Setup',
292	        '',
293	        'The LayerInfinite MCP Gateway Proxy transparently enriches your existing MCP tools with historical outcome intelligence.',
294	        '',
295	        '## Configuration',
296	        '',
297	        'Set these environment variables before starting:',
298	        '',
299	        '| Variable | Required | Description |',
300	        '|----------|----------|-------------|',
301	        '| `LAYERINFINITE_API_KEY` | Yes | Your LayerInfinite API key |',
302	        '| `LAYERINFINITE_UPSTREAM_TOOLS` | Yes | JSON array of upstream MCP servers (name, url, optional apiKey) |',
303	        '| `LAYERINFINITE_MODE` | No | Operating mode: `recommend`, `assist`, `auto` (omit for bootstrap) |',
304	        '| `LAYERINFINITE_MODE_OVERRIDES` | No | Per-task-type mode overrides as JSON object |',
305	        '| `LAYERINFINITE_SHADOW_MODE` | No | Set to `true` to observe without intervening |',
306	        '| `LAYERINFINITE_ENVIRONMENT` | No | `staging` or `production` (default: production) |',
307	        '| `LAYERINFINITE_BASE_URL` | No | API base URL (default: https://layerinfinite.me) |',
308	        '',
309	        '## Modes',
310	        '',
311	        '- **Bootstrap** (no mode set): Observe only — no enrichment or intervention',
312	        '- **Recommend**: Tool descriptions enriched with historical success rates',
313	        '- **Assist**: Recommendations + directional warnings based on history',
314	        '- **Auto**: Silent rerouting to the best tool based on outcome data',
315	        '',
316	        '## Upstream Format',
317	        '',
318	        '```json',
319	        '[',
320	        '  { "name": "github", "url": "https://github-mcp.example.com", "apiKey": "sk-..." },',
321	        '  { "name": "filesystem", "url": "http://localhost:8080" }',
322	        ']',
323	        '```',
324	        '',
325	        '## Starting the Gateway',
326	        '',
327	        '```bash',
328	        'npx @layerinfinite/mcp-server',
329	        '# or directly:',
330	        'node dist/bin/cli.js',
331	        '```',
332	        '',
333	        'The gateway connects via stdio — configure your MCP client to spawn this process.',
334	      ].join('\n');
335	
336	      return {
337	        messages: [
338	          {
339	            role: 'user' as const,
340	            content: { type: 'text' as const, text },
341	          },
342	        ],
343	      };
344	    },
345	  );
346	
347	  log.info('Gateway server created', {
348	    mode: config.mode ?? 'bootstrap',
349	    upstreams: config.upstreamServers.length,
350	    environment: config.environment,
351	    shadowMode: config.shadowMode,
352	  });
353	
354	  return { server, proxy, config, upstreamClient, registry };
355	}
356	
