149	  // ── HTTP helpers (preserved from V1) ─────────────────────
150	
151	  private async get<T>(
152	    path: string,
153	    params?: Record<string, string>,
154	  ): Promise<LIResult<T>> {
155	    const url = new URL(`${this.baseUrl}${path}`);
156	    if (params) {
157	      for (const [key, value] of Object.entries(params)) {
158	        if (value !== undefined && value !== '') {
159	          url.searchParams.set(key, value);
160	        }
161	      }
162	    }
163	    return this.requestWithRetry<T>(url.toString(), { method: 'GET' });
164	  }
165	
166	  private async post<T>(
167	    path: string,
168	    body: Record<string, unknown>,
169	  ): Promise<LIResult<T>> {
170	    return this.requestWithRetry<T>(`${this.baseUrl}${path}`, {
171	      method: 'POST',
172	      body: JSON.stringify(body),
173	    });
174	  }
175	
176	  private async requestWithRetry<T>(
177	    url: string,
178	    init: RequestInit,
179	  ): Promise<LIResult<T>> {
180	    let lastResult: LIResult<T> | null = null;
181	
182	    for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
183	      if (attempt > 0) {
184	        const delay = BASE_RETRY_DELAY_MS * Math.pow(2, attempt - 1);
185	        log.warn('Retrying LI API request', { url, attempt: attempt + 1, delay_ms: delay });
186	        await this.sleep(delay);
187	      }
188	
189	      const result = await this.request<T>(url, init);
190	      if (result.ok) return result;
191	
192	      lastResult = result;
193	      const isRetryable = RETRYABLE_STATUS_CODES.has(result.status)
194	        || result.error.code === 'TIMEOUT'
195	        || result.error.code === 'NETWORK_ERROR';
196	      if (!isRetryable) break;
197	    }
198	
199	    return lastResult!;
200	  }
201	
202	  private async request<T>(
203	    url: string,
204	    init: RequestInit,
205	  ): Promise<LIResult<T>> {
206	    const controller = new AbortController();
207	    const timeout = setTimeout(() => controller.abort(), LI_API_TIMEOUT_MS);
208	    const startMs = Date.now();
209	
210	    try {
211	      const response = await fetch(url, {
212	        ...init,
213	        headers: { ...this.headers, ...(init.headers as Record<string, string> ?? {}) },
214	        signal: controller.signal,
215	      });
216	
217	      const latencyMs = Date.now() - startMs;
218	      const isJson = response.headers.get('content-type')?.includes('application/json');
219	
220	      if (response.ok) {
221	        const data = isJson ? (await response.json()) as T : ({} as T);
222	        log.debug('LI API response', { method: init.method, url, status: response.status, latency_ms: latencyMs });
223	        return { ok: true, status: response.status, data };
224	      }
225	
226	      const errorBody: LIApiError = isJson
227	        ? (await response.json()) as LIApiError
228	        : { error: 'API Error', code: 'UNKNOWN', message: await response.text() };
229	
230	      log.warn('LI API error', { method: init.method, url, status: response.status, error_code: errorBody.code });
231	      return { ok: false, status: response.status, error: errorBody };
232	    } catch (err) {
233	      const latencyMs = Date.now() - startMs;
234	      if (err instanceof DOMException && err.name === 'AbortError') {
235	        log.error('LI API timeout', { method: init.method, url, timeout_ms: LI_API_TIMEOUT_MS });
236	        return {
237	          ok: false,
238	          status: 0,
239	          error: { error: 'Request timed out', code: 'TIMEOUT', message: `Request timed out after ${LI_API_TIMEOUT_MS}ms` },
240	        };
241	      }
242	
243	      const message = err instanceof Error ? err.message : String(err);
244	      log.error('LI API network error', { method: init.method, url, error: message });
245	      return {
246	        ok: false,
247	        status: 0,
248	        error: { error: 'Network error', code: 'NETWORK_ERROR', message },
249	      };
250	    } finally {
251	      clearTimeout(timeout);
252	    }
253	  }
254	
255	  private sleep(ms: number): Promise<void> {
256	    return new Promise((resolve) => setTimeout(resolve, ms));
257	  }
258	}
