1	/**
2	 * LayerInfinite MCP Server — tool-enrichment.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Enrichment engine. Orchestrates per-mode description formatting
5	 * for every tool returned by upstream servers. CRITICAL: inputSchema
6	 * is NEVER modified — only description is enriched.
7	 * ══════════════════════════════════════════════════════════════
8	 */
9	
10	import type { EnrichedTool, EnrichmentContext, ScoredAction, GatewayMode } from './types.js';
11	import type { RawUpstreamTool } from './rest-client.js';
12	import { formatRecommendEnrichment } from './enrichment/format-recommend.js';
13	import { formatAssistEnrichment } from './enrichment/format-assist.js';
14	import type { AssistFormatContext } from './enrichment/format-assist.js';
15	import { logger } from './logger.js';
16	
17	const log = logger.forTool('tool-enrichment');
18	
19	/**
20	 * Enrich a list of upstream tools with historical outcome data.
21	 * Adds annotations (ranking, category) for internal use.
22	 * inputSchema is passed through unmodified.
23	 */
24	export function enrichToolList(
25	  tools: RawUpstreamTool[],
26	  context: EnrichmentContext,
27	): EnrichedTool[] {
28	  const { mode, scores, taskType } = context;
29	
30	  // Build score lookup
31	  const scoreMap = new Map<string, ScoredAction>();
32	  for (const s of scores) {
33	    scoreMap.set(s.actionName, s);
34	  }
35	
36	  // Rank by composite score descending
37	  const ranked = [...scores].sort((a, b) => b.compositeScore - a.compositeScore);
38	  const bestScore = ranked[0] ?? null;
39	
40	  return tools.map((tool) => {
41	    const score = scoreMap.get(tool.name) ?? null;
42	    const rank = score
43	      ? ranked.findIndex((s) => s.actionName === tool.name) + 1
44	      : null;
45	
46	    const enrichedDesc =
47	      mode === 'bootstrap'
48	        ? tool.description
49	        : enrichDescription(mode, tool, taskType, score, rank, tools.length, bestScore);
50	
51	    return {
52	      name: tool.name,
53	      description: enrichedDesc,
54	      inputSchema: tool.inputSchema, // UNMODIFIED — passthrough from upstream
55	      upstreamName: tool.upstreamName,
56	      annotations: {
57	        ranking: rank ?? undefined,
58	        category: categorize(score),
59	      },
60	    };
61	  });
62	}
63	
64	function enrichDescription(
65	  mode: GatewayMode,
66	  tool: RawUpstreamTool,
67	  taskType: string,
68	  score: ScoredAction | null,
69	  rank: number | null,
70	  totalTools: number,
71	  bestScore: ScoredAction | null,
72	): string {
73	  switch (mode) {
74	    case 'recommend':
75	      return formatRecommendEnrichment(
76	        tool.description,
77	        tool.name,
78	        taskType,
79	        score,
80	        rank,
81	      );
82	
83	    case 'assist':
84	    case 'auto': {
85	      const ctx: AssistFormatContext = {
86	        toolName: tool.name,
87	        taskType,
88	        description: tool.description,
89	        score,
90	        rank,
91	        totalTools,
92	        bestScore,
93	      };
94	      return formatAssistEnrichment(ctx);
95	    }
96	
97	    default:
98	      return tool.description;
99	  }
100	}
101	
102	function categorize(
103	  score: ScoredAction | null,
104	): 'recommended' | 'neutral' | 'warning' | undefined {
105	  if (!score || score.sampleSize < 3) return undefined;
106	  if (score.compositeScore >= 0.7) return 'recommended';
107	  if (score.compositeScore >= 0.4) return 'neutral';
108	  return 'warning';
109	}
