1	/**
2	 * LayerInfinite MCP Server — mode-manager.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Per-task-type mode resolution with caching. Checks overrides
5	 * first, falls back to global mode, caches result for 5 minutes.
6	 * ══════════════════════════════════════════════════════════════
7	 */
8	
9	import type { GatewayConfig, LIMode } from './config.js';
10	import type { GatewayMode } from './types.js';
11	
12	const MODE_CACHE_TTL_MS = 5 * 60 * 1000;
13	
14	interface ModeCacheEntry {
15	  mode: GatewayMode;
16	  resolvedAt: number;
17	}
18	
19	export class ModeManager {
20	  private readonly cache = new Map<string, ModeCacheEntry>();
21	
22	  constructor(private readonly config: GatewayConfig) {}
23	
24	  /**
25	   * Resolve the effective mode for a task type.
26	   * Overrides (per-task-type) take precedence over global mode.
27	   * Cached for 5 min per task type.
28	   */
29	  resolveMode(taskType: string): GatewayMode {
30	    const cached = this.cache.get(taskType);
31	    if (cached && Date.now() - cached.resolvedAt < MODE_CACHE_TTL_MS) {
32	      return cached.mode;
33	    }
34	
35	    // If global mode is null (bootstrap), everything is bootstrap
36	    if (this.config.mode === null) {
37	      return this.cacheAndReturn(taskType, 'bootstrap');
38	    }
39	
40	    // Check per-task-type override
41	    const override = this.config.modeOverrides.get(taskType);
42	    const mode = override ?? this.config.mode;
43	
44	    return this.cacheAndReturn(taskType, mode);
45	  }
46	
47	  /** Get the global mode (without per-task overrides). */
48	  getGlobalMode(): GatewayMode {
49	    return this.config.mode ?? 'bootstrap';
50	  }
51	
52	  /** Clear mode resolution cache. */
53	  clearCache(): void {
54	    this.cache.clear();
55	  }
56	
57	  private cacheAndReturn(taskType: string, mode: GatewayMode): GatewayMode {
58	    this.cache.set(taskType, { mode, resolvedAt: Date.now() });
59	    return mode;
60	  }
61	}
