1	/**
2	 * LayerInfinite MCP Server — upstream-registry.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Manages upstream MCP server connections: registration, health
5	 * checks, circuit breaker integration, and tool discovery.
6	 * ══════════════════════════════════════════════════════════════
7	 */
8	
9	import type { UpstreamServer, GatewayConfig } from './config.js';
10	import {
11	  createFailOpenState,
12	  recordUpstreamFailure,
13	  recordUpstreamSuccess,
14	  probeCircuitBreaker,
15	  updateHealthCheck,
16	  isCircuitOpen,
17	} from './fail-open.js';
18	import type { FailOpenState } from './types.js';
19	import { logger } from './logger.js';
20	
21	const log = logger.forTool('upstream-registry');
22	
23	const DEFAULT_HEALTH_CHECK_MS = 30_000;
24	const HEALTH_PING_TIMEOUT_MS = 5_000;
25	
26	export interface UpstreamEntry {
27	  server: UpstreamServer;
28	  healthy: boolean;
29	  lastCheck: number;
30	  lastError?: string;
31	}
32	
33	export class UpstreamRegistry {
34	  private readonly servers: Map<string, UpstreamEntry> = new Map();
35	  private readonly state: FailOpenState;
36	  private healthCheckTimer: ReturnType<typeof setInterval> | null = null;
37	  private shutdownFlag = false;
38	
39	  constructor(config: GatewayConfig) {
40	    this.state = createFailOpenState();
41	    for (const server of config.upstreamServers) {
42	      this.servers.set(server.name, {
43	        server,
44	        healthy: true, // Start optimistic — first health check will correct
45	        lastCheck: 0,
46	      });
47	      log.info('Registered upstream', { name: server.name, url: server.url });
48	    }
49	  }
50	
51	  /** Get a single upstream by name. */
52	  getUpstream(name: string): UpstreamEntry | undefined {
53	    return this.servers.get(name);
54	  }
55	
56	  /** Get all upstream server configs. */
57	  getAllUpstreams(): UpstreamEntry[] {
58	    return Array.from(this.servers.values());
59	  }
60	
61	  /** Check if an upstream is healthy (circuit closed + recent health check OK). */
62	  isHealthy(name: string): boolean {
63	    const entry = this.servers.get(name);
64	    if (!entry) return false;
65	    if (isCircuitOpen(this.state, name)) return false;
66	    return entry.healthy;
67	  }
68	
69	  /** Get the FailOpenState for external circuit breaker queries. */
70	  getFailOpenState(): FailOpenState {
71	    return this.state;
72	  }
73	
74	  /**
75	   * Start periodic health checks for all upstream servers.
76	   * Each upstream gets its own check interval (default 30s).
77	   */
78	  startHealthChecks(): void {
79	    if (this.healthCheckTimer) return;
80	
81	    // Run initial checks immediately
82	    void this.checkAllUpstreams();
83	
84	    this.healthCheckTimer = setInterval(() => {
85	      if (this.shutdownFlag) return;
86	      void this.checkAllUpstreams();
87	    }, DEFAULT_HEALTH_CHECK_MS);
88	
89	    log.info('Health checks started', { upstreams: this.servers.size });
90	  }
91	
92	  /** Stop the health check loop. */
93	  stopHealthChecks(): void {
94	    this.shutdownFlag = true;
95	    if (this.healthCheckTimer) {
96	      clearInterval(this.healthCheckTimer);
97	      this.healthCheckTimer = null;
98	      log.info('Health checks stopped');
99	    }
100	  }
101	
102	  private async checkAllUpstreams(): Promise<void> {
103	    const checks = Array.from(this.servers.values()).map((entry) =>
104	      this.checkUpstream(entry),
105	    );
106	    await Promise.allSettled(checks);
107	  }
108	
109	  private async checkUpstream(entry: UpstreamEntry): Promise<void> {
110	    const { server } = entry;
111	    const interval = server.healthCheckIntervalMs ?? DEFAULT_HEALTH_CHECK_MS;
112	
113	    // Skip if checked recently
114	    if (Date.now() - entry.lastCheck < interval) return;
115	
116	    // Check if circuit breaker allows probing
117	    probeCircuitBreaker(this.state, server.name);
118	    updateHealthCheck(this.state, server.name);
119	
120	    try {
121	      const controller = new AbortController();
122	      const timeout = setTimeout(() => controller.abort(), HEALTH_PING_TIMEOUT_MS);
123	
124	      const response = await fetch(`${server.url}/health`, {
125	        method: 'GET',
126	        headers: server.apiKey
127	          ? { Authorization: `Bearer ${server.apiKey}` }
128	          : {},
129	        signal: controller.signal,
130	      });
131	
132	      clearTimeout(timeout);
133	
134	      if (response.ok) {
135	        entry.healthy = true;
136	        entry.lastCheck = Date.now();
137	        entry.lastError = undefined;
138	        recordUpstreamSuccess(this.state, server.name);
139	        log.debug('Upstream healthy', { name: server.name });
140	      } else {
141	        entry.healthy = false;
142	        entry.lastCheck = Date.now();
143	        entry.lastError = `HTTP ${response.status}`;
144	        recordUpstreamFailure(this.state, server.name);
145	        log.warn('Upstream unhealthy', {
146	          name: server.name,
147	          status: response.status,
148	        });
149	      }
150	    } catch (err) {
151	      entry.healthy = false;
152	      entry.lastCheck = Date.now();
153	      entry.lastError = err instanceof Error ? err.message : String(err);
154	      recordUpstreamFailure(this.state, server.name);
155	      log.warn('Upstream health check failed', {
156	        name: server.name,
157	        error: entry.lastError,
158	      });
159	    }
160	  }
161	}
