1	/**
2	 * LayerInfinite MCP Server — decision-tracker.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Decision ID generation + episode tracking + buffer flush.
5	 * Replaces episode-tracker.ts (V1 redirect-loop prevention).
6	 *
7	 * Decision ID format: dec_{ts12}_{agent4}_{rand4}
8	 *   ts12    — base62-encoded timestamp (lexicographically sortable)
9	 *   agent4  — base62-encoded djb2 hash of agentId
10	 *   rand4   — 4 random base62 chars (collision prob < 10^-9 per ms)
11	 *
12	 * Buffer flushes every 5s to LI API. Disk queue fallback at
13	 * .li-queue/decisions.jsonl when API is unreachable.
14	 * ══════════════════════════════════════════════════════════════
15	 */
16	
17	import { appendFileSync, mkdirSync, existsSync } from 'node:fs';
18	import { join } from 'node:path';
19	import type { DecisionRecord, Episode } from './types.js';
20	import type { LiApiClient } from './rest-client.js';
21	import { logger } from './logger.js';
22	
23	const log = logger.forTool('decision-tracker');
24	
25	// ── Decision ID generation ──────────────────────────────────
26	
27	const BASE62 = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz';
28	const FLUSH_INTERVAL_MS = 5_000;
29	const EPISODE_TTL_MS = 30 * 60 * 1000;
30	const MAX_COACHING_PER_EPISODE = 3;
31	const DISK_QUEUE_DIR = '.li-queue';
32	const DISK_QUEUE_FILE = 'decisions.jsonl';
33	
34	function base62Encode(n: number, minLen: number): string {
35	  let s = '';
36	  let v = n;
37	  while (v > 0) {
38	    s = BASE62[v % 62] + s;
39	    v = Math.floor(v / 62);
40	  }
41	  return s.padStart(minLen, '0');
42	}
43	
44	function djb2(s: string): number {
45	  let hash = 5381;
46	  for (let i = 0; i < s.length; i++) {
47	    hash = ((hash << 5) + hash) + s.charCodeAt(i);
48	    hash = hash >>> 0;
49	  }
50	  return hash;
51	}
52	
53	function randomBase62(len: number): string {
54	  let s = '';
55	  for (let i = 0; i < len; i++) {
56	    s += BASE62[Math.floor(Math.random() * 62)];
57	  }
58	  return s;
59	}
60	
61	export function generateDecisionId(agentId: string): string {
62	  const ts12 = base62Encode(Date.now(), 12);
63	  const agent4 = base62Encode(djb2(agentId), 4).slice(0, 4);
64	  const rand4 = randomBase62(4);
65	  return `dec_${ts12}_${agent4}_${rand4}`;
66	}
67	
68	function generateEpisodeId(): string {
69	  const ts10 = base62Encode(Date.now(), 10);
70	  const rand6 = randomBase62(6);
71	  return `ep_${ts10}_${rand6}`;
72	}
73	
74	// ══════════════════════════════════════════════════════════════
75	// DecisionTracker
76	// ══════════════════════════════════════════════════════════════
77	
78	export class DecisionTracker {
79	  private readonly episodes = new Map<string, Episode>();
80	  private readonly buffer: DecisionRecord[] = [];
81	  private flushTimer: ReturnType<typeof setInterval> | null = null;
82	  private flushing = false;
83	  private queueDirEnsured = false;
84	
85	  constructor(private readonly liApi: LiApiClient) {}
86	
87	  // ── Episode management ───────────────────────────────────
88	
89	  startEpisode(agentId: string, customerId: string): Episode {
90	    this.cleanExpiredEpisodes();
91	
92	    const episode: Episode = {
93	      episodeId: generateEpisodeId(),
94	      agentId,
95	      sessionStart: new Date().toISOString(),
96	      decisions: [],
97	      coachingCount: 0,
98	    };
99	
100	    this.episodes.set(episode.episodeId, episode);
101	    log.debug('Episode started', { episodeId: episode.episodeId, agentId, customerId });
102	    return episode;
103	  }
104	
105	  getEpisode(episodeId: string): Episode | undefined {
106	    this.cleanExpiredEpisodes();
107	    return this.episodes.get(episodeId);
108	  }
109	
110	  /** Record a coaching injection. Returns false if cap (3) already reached. */
111	  recordCoaching(episodeId: string): boolean {
112	    const episode = this.episodes.get(episodeId);
113	    if (!episode) return false;
114	    if (episode.coachingCount >= MAX_COACHING_PER_EPISODE) return false;
115	    episode.coachingCount++;
116	    return true;
117	  }
118	
119	  canCoach(episodeId: string): boolean {
120	    const episode = this.episodes.get(episodeId);
121	    if (!episode) return true; // No episode yet — coaching is allowed
122	    return episode.coachingCount < MAX_COACHING_PER_EPISODE;
123	  }
124	
125	  // ── Decision recording ───────────────────────────────────
126	
127	  recordDecision(record: DecisionRecord): void {
128	    this.buffer.push(record);
129	
130	    // Link to episode
131	    if (this.episodes.size > 0) {
132	      // Find the most recent episode for this agent
133	      let latest: Episode | undefined;
134	      for (const ep of this.episodes.values()) {
135	        if (ep.agentId === record.agentId) {
136	          if (!latest || ep.sessionStart > latest.sessionStart) {
137	            latest = ep;
138	          }
139	        }
140	      }
141	      if (latest) {
142	        latest.decisions.push(record.decisionId);
143	      }
144	    }
145	
146	    // Append to disk queue for durability
147	    this.appendToDiskQueue(record);
148	
149	    log.debug('Decision recorded', { decisionId: record.decisionId });
150	  }
151	
152	  // ── Flush ────────────────────────────────────────────────
153	
154	  async flushBuffer(): Promise<void> {
155	    if (this.buffer.length === 0 || this.flushing) return;
156	
157	    this.flushing = true;
158	    const batch = this.buffer.splice(0);
159	
160	    try {
161	      // Send each decision's outcome to LI API
162	      for (const record of batch) {
163	        const sent = await this.liApi.logOutcome({
164	          decision_id: record.decisionId,
165	          agent_id: record.agentId,
166	          customer_id: record.customerId,
167	          task_type: record.taskType,
168	          action_name: record.actionName,
169	          upstream_name: record.upstreamName,
170	          original_action: record.originalAction,
171	          executed_action: record.executedAction,
172	          mode: record.mode,
173	          rerouted: record.rerouted,
174	          latency_ms: 0,
175	          timestamp: record.timestamp,
176	          ingestion_source: 'mcp',
177	          environment: 'production',
178	        });
179	
180	        if (!sent) {
181	          // Re-queue on failure
182	          this.buffer.push(record);
183	        }
184	      }
185	    } catch (err) {
186	      log.warn('Buffer flush failed — re-queuing', {
187	        count: batch.length,
188	        error: err instanceof Error ? err.message : String(err),
189	      });
190	      this.buffer.push(...batch);
191	    } finally {
192	      this.flushing = false;
193	    }
194	  }
195	
196	  startFlushTimer(): void {
197	    if (this.flushTimer) return;
198	    this.flushTimer = setInterval(() => {
199	      void this.flushBuffer();
200	    }, FLUSH_INTERVAL_MS);
201	  }
202	
203	  stopFlushTimer(): void {
204	    if (this.flushTimer) {
205	      clearInterval(this.flushTimer);
206	      this.flushTimer = null;
207	    }
208	  }
209	
210	  // ── Stats ────────────────────────────────────────────────
211	
212	  get bufferSize(): number {
213	    return this.buffer.length;
214	  }
215	
216	  get episodeCount(): number {
217	    this.cleanExpiredEpisodes();
218	    return this.episodes.size;
219	  }
220	
221	  // ── Private ──────────────────────────────────────────────
222	
223	  private appendToDiskQueue(record: DecisionRecord): void {
224	    try {
225	      if (!this.queueDirEnsured) {
226	        if (!existsSync(DISK_QUEUE_DIR)) {
227	          mkdirSync(DISK_QUEUE_DIR, { recursive: true });
228	        }
229	        this.queueDirEnsured = true;
230	      }
231	      appendFileSync(
232	        join(DISK_QUEUE_DIR, DISK_QUEUE_FILE),
233	        JSON.stringify(record) + '\n',
234	        'utf-8',
235	      );
236	    } catch {
237	      // Disk queue is best-effort — silent failure is acceptable
238	    }
239	  }
240	
241	  private cleanExpiredEpisodes(): void {
242	    const cutoff = Date.now() - EPISODE_TTL_MS;
243	    for (const [id, ep] of this.episodes) {
244	      if (new Date(ep.sessionStart).getTime() < cutoff) {
245	        this.episodes.delete(id);
246	      }
247	    }
248	  }
249	}
