1	/**
2	 * LayerInfinite MCP Server — logger.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Structured JSON logger to stderr (stdout is reserved for MCP
5	 * protocol messages over stdio transport).
6	 *
7	 * Production-grade: every log line is a JSON object with timestamp,
8	 * level, tool name, and structured data. Parseable by any log
9	 * aggregator (Datadog, Grafana Loki, CloudWatch, etc).
10	 * ══════════════════════════════════════════════════════════════
11	 */
12	
13	export type LogLevel = 'debug' | 'info' | 'warn' | 'error';
14	
15	const LEVEL_PRIORITY: Record<LogLevel, number> = {
16	  debug: 0,
17	  info: 1,
18	  warn: 2,
19	  error: 3,
20	};
21	
22	const MIN_LEVEL: LogLevel = (process.env.LAYERINFINITE_LOG_LEVEL as LogLevel) ?? 'info';
23	
24	export interface LogEntry {
25	  ts: string;
26	  level: LogLevel;
27	  tool?: string;
28	  msg: string;
29	  [key: string]: unknown;
30	}
31	
32	function shouldLog(level: LogLevel): boolean {
33	  return LEVEL_PRIORITY[level] >= LEVEL_PRIORITY[MIN_LEVEL];
34	}
35	
36	function emit(entry: LogEntry): void {
37	  if (!shouldLog(entry.level)) return;
38	  process.stderr.write(JSON.stringify(entry) + '\n');
39	}
40	
41	export const logger = {
42	  debug(msg: string, data?: Record<string, unknown>) {
43	    emit({ ts: new Date().toISOString(), level: 'debug', msg, ...data });
44	  },
45	  info(msg: string, data?: Record<string, unknown>) {
46	    emit({ ts: new Date().toISOString(), level: 'info', msg, ...data });
47	  },
48	  warn(msg: string, data?: Record<string, unknown>) {
49	    emit({ ts: new Date().toISOString(), level: 'warn', msg, ...data });
50	  },
51	  error(msg: string, data?: Record<string, unknown>) {
52	    emit({ ts: new Date().toISOString(), level: 'error', msg, ...data });
53	  },
54	
55	  /** Scoped logger that includes tool name in every log line. */
56	  forTool(toolName: string) {
57	    return {
58	      debug: (msg: string, data?: Record<string, unknown>) =>
59	        emit({ ts: new Date().toISOString(), level: 'debug', tool: toolName, msg, ...data }),
60	      info: (msg: string, data?: Record<string, unknown>) =>
61	        emit({ ts: new Date().toISOString(), level: 'info', tool: toolName, msg, ...data }),
62	      warn: (msg: string, data?: Record<string, unknown>) =>
63	        emit({ ts: new Date().toISOString(), level: 'warn', tool: toolName, msg, ...data }),
64	      error: (msg: string, data?: Record<string, unknown>) =>
65	        emit({ ts: new Date().toISOString(), level: 'error', tool: toolName, msg, ...data }),
66	    };
67	  },
68	};
