34	async function fetchDataSources(
35	    customerId: string,
36	    agentId: string,
37	    taskName: string,
38	): Promise<{
39	    uploaded_outcomes: number;
40	    sdk_outcomes: number;
41	    mcp_outcomes: number;
42	    total: number;
43	    upload_share: number;
44	    quality_score: number | null;
45	}> {
46	    try {
47	        const normalizedTask = normalizeTaskSlug(taskName);
48	        const candidates = normalizedTask && normalizedTask !== taskName
49	            ? [taskName, normalizedTask]
50	            : [taskName];
51	
52	        let finalCandidate = candidates[0];
53	        let importedCount = 0;
54	        let sdkCount = 0;
55	        let mcpCount = 0;
56	
57	        for (const candidate of candidates) {
58	            const baseQuery = supabase
59	                .from('fact_outcomes')
60	                .select('*', { count: 'exact', head: true })
61	                .eq('customer_id', customerId)
62	                .eq('agent_id', agentId)
63	                .eq('task_name', candidate)
64	                .eq('is_synthetic', false)
65	                .eq('is_deleted', false);
66	
67	            const [importRes, sdkRes, mcpRes] = await Promise.all([
68	                baseQuery.eq('ingestion_source', 'import'),
69	                baseQuery.eq('ingestion_source', 'api'),
70	                baseQuery.eq('ingestion_source', 'mcp')
71	            ]);
72	            
73	            // If we found data using this slug, stick with it.
74	            if ((importRes.count ?? 0) > 0 || (sdkRes.count ?? 0) > 0 || (mcpRes.count ?? 0) > 0) {
75	                importedCount = importRes.count ?? 0;
76	                sdkCount = sdkRes.count ?? 0;
77	                mcpCount = mcpRes.count ?? 0;
78	                finalCandidate = candidate;
79	                break;
80	            }
81	        }
82	
83	        const total = importedCount + sdkCount + mcpCount;
84	        if (total === 0) {
85	            return { uploaded_outcomes: 0, sdk_outcomes: 0, mcp_outcomes: 0, total: 0, upload_share: 0, quality_score: null };
86	        }
87	
88	        // Fetch just a 1000-row sample for the average quality to prevent OOM
89	        const { data: qualityRows } = await supabase
