500	// ── GET /task-analytics ──────────────────────────────────────
501	// Computes three signals the main recommendation response doesn't include:
502	//   1. Drift trendline — sliding-window linear regression on success rate over
503	//      the last N outcomes, giving slope + confidence so the UI can show
504	//      "success rate is silently dropping" before it hits the noise gate.
505	//   2. Explore/exploit ratio — fraction of outcomes that were exploration events
506	//      (cross_event_status != 'none' or is_synthetic) vs exploitation.
507	//   3. Trust blocks — how many outcomes were blocked/logged while trust_status
508	//      was below threshold (recorded via execution_status='FAILED' + failure_reason_code='TRUST_GATE').
509	//
510	// All queries are read-only against fact_outcomes.
511	// Required query params: task (string), agent_id (UUID)
512	// Optional: window (integer, default 50) — outcome count for drift window
513	getRecommendationsRouter.get('/task-analytics', async (c) => {
514	    c.header('Cache-Control', 'no-store');
515	    const customerId = c.get('customer_id') as string | undefined;
516	    if (!customerId) {
517	        return c.json({ error: 'Unauthorized', code: 'MISSING_CUSTOMER_ID' }, 401);
518	    }
519	
520	    const rawTask = c.req.query('task')?.trim() || null;
521	    const rawAgentId = c.req.query('agent_id')?.trim() || null;
522	    const windowSize = Math.max(20, Math.min(200, parseInt(c.req.query('window') ?? '50', 10) || 50));
523	
524	    if (!rawTask) {
525	        return c.json({ error: 'Missing required query parameter: task', code: 'MISSING_TASK' }, 400);
526	    }
527	    if (!rawAgentId) {
528	        return c.json({ error: 'Missing required query parameter: agent_id', code: 'MISSING_AGENT_ID' }, 400);
529	    }
530	
531	    try {
532	        // Run drift-window query and action-aggregate query in parallel.
533	        // The drift query is limited to a recent window; action aggregates are all-time.
534	        // Action aggregates are needed when trust gate blocks the engine (all_actions=[]).
535	        const [driftResult, actionResult] = await Promise.all([
536	            supabase
537	                .from('fact_outcomes')
538	                .select('success, outcome_score, outcome_score_raw, execution_status, failure_reason_code, cross_event_status, is_synthetic, timestamp, data_quality')
539	                .eq('customer_id', customerId)
540	                .eq('agent_id', rawAgentId)
541	                .eq('task_name', rawTask)
542	                .eq('is_deleted', false)
543	                .eq('is_synthetic', false)
544	                .order('timestamp', { ascending: false })
545	                .limit(windowSize * 2),
546	            supabase
547	                .from('fact_outcomes')
548	                .select('action_id, outcome_score, outcome_score_raw, success, execution_status, timestamp, dim_actions(action_name)')
549	                .eq('customer_id', customerId)
550	                .eq('agent_id', rawAgentId)
551	                .eq('task_name', rawTask)
552	                .eq('is_deleted', false)
553	                .eq('is_synthetic', false)
554	                .order('timestamp', { ascending: false })
555	                .limit(5000),
556	        ]);
557	
558	        if (driftResult.error) {
559	            throw new Error(`[task-analytics] drift query failed: ${driftResult.error.message}`);
560	        }
561	
562	        const rows = (driftResult.data ?? []) as Array<{
563	            success: boolean | null;
564	            outcome_score: number | null;
565	            outcome_score_raw: number | null;
566	            execution_status: string | null;
567	            failure_reason_code: string | null;
568	            cross_event_status: string | null;
569	            is_synthetic: boolean | null;
570	            timestamp: string | null;
571	            data_quality: number | null;
572	        }>;
573	
574	        // ── Action aggregates (for trust-blocked fallback) ────
575	        type ActionAgg = { action_id: string; action_name: string; total_count: number; score_sum: number; score_count: number; last_seen_at: string | null };
576	        const actionAggMap = new Map<string, ActionAgg>();
577	        for (const raw of (actionResult.data ?? []) as Array<Record<string, unknown>>) {
578	            const actionId = typeof raw.action_id === 'string' ? raw.action_id : null;
579	            if (!actionId) continue;
580	            const rel = raw.dim_actions;
581	            const actionName: string = (Array.isArray(rel) ? (rel[0] as any)?.action_name : (rel as any)?.action_name) ?? actionId;
582	            const rawScore = typeof raw.outcome_score_raw === 'number' ? raw.outcome_score_raw
583	                : typeof raw.outcome_score === 'number' ? raw.outcome_score : null;
584	            const statusScore = typeof raw.execution_status === 'string'
585	                ? (raw.execution_status.toUpperCase() === 'COMPLETED' ? 1 : raw.execution_status.toUpperCase() === 'FAILED' ? 0 : null)
586	                : null;
587	            const score = rawScore ?? statusScore ?? (raw.success === true ? 1 : raw.success === false ? 0 : null);
588	            const ts = typeof raw.timestamp === 'string' ? raw.timestamp : null;
589	            const key = actionId;
590	            const agg = actionAggMap.get(key) ?? { action_id: actionId, action_name: actionName, total_count: 0, score_sum: 0, score_count: 0, last_seen_at: null };
591	            agg.total_count += 1;
592	            if (score !== null) { agg.score_sum += score; agg.score_count += 1; }
593	            if (ts && (!agg.last_seen_at || ts > agg.last_seen_at)) agg.last_seen_at = ts;
594	            actionAggMap.set(key, agg);
595	        }
596	        const actionAggregates = Array.from(actionAggMap.values())
597	            .map((a) => ({
598	                action_id: a.action_id,
599	                action_name: a.action_name,
600	                total_count: a.total_count,
601	                effective_sample_count: a.total_count,
602	                resolution_rate: a.score_count > 0 ? Number((a.score_sum / a.score_count).toFixed(4)) : 0,
603	                ml_score: null,
604	                semantic_cluster_convergence: null,
605	                last_seen_at: a.last_seen_at,
606	            }))
607	            .sort((a, b) => b.resolution_rate - a.resolution_rate);
608	
609	        if (rows.length === 0 && actionAggregates.length === 0) {
610	            return c.json({
611	                drift: { slope: null, confidence: null, window_size: 0, direction: 'unknown', points: [] },
612	                explore_exploit: { explore_count: 0, exploit_count: 0, total: 0, explore_ratio: null },
613	                trust_blocks: { blocked_count: 0, total: 0 },
614	                action_aggregates: [],
615	            }, 200);
616	        }
617	
618	        // ── 1. Drift trendline ────────────────────────────────
619	        // Reverse to chronological order, take last `windowSize`.
620	        // Use a 5-outcome sliding window to compute local success rate at each step,
621	        // then run linear regression (OLS) on those rates vs. position index.
622	        const chronological = [...rows].reverse().slice(-windowSize);
623	        const SLIDING = 5;
624	        const points: Array<{ index: number; rate: number; timestamp: string }> = [];
625	
626	        for (let i = SLIDING - 1; i < chronological.length; i++) {
627	            const slice = chronological.slice(i - SLIDING + 1, i + 1);
628	            let successSum = 0;
629	            let count = 0;
630	            for (const r of slice) {
631	                const score = typeof r.outcome_score === 'number' ? r.outcome_score
632	                    : typeof r.outcome_score_raw === 'number' ? r.outcome_score_raw
633	                        : typeof r.success === 'boolean' ? (r.success ? 1 : 0)
634	                            : null;
635	                if (score !== null) {
636	                    successSum += score;
637	                    count++;
638	                }
639	            }
640	            if (count > 0) {
641	                points.push({
642	                    index: i,
643	                    rate: Number((successSum / count).toFixed(4)),
644	                    timestamp: chronological[i]!.timestamp ?? '',
645	                });
646	            }
647	        }
648	
649	        let slope: number | null = null;
650	        let rSquared: number | null = null;
651	
652	        if (points.length >= 4) {
653	            const n = points.length;
654	            const xs = points.map((p) => p.index);
655	            const ys = points.map((p) => p.rate);
656	            const xMean = xs.reduce((a, b) => a + b, 0) / n;
657	            const yMean = ys.reduce((a, b) => a + b, 0) / n;
658	            const ssXY = xs.reduce((acc, x, i) => acc + (x - xMean) * (ys[i]! - yMean), 0);
659	            const ssXX = xs.reduce((acc, x) => acc + (x - xMean) ** 2, 0);
660	            const ssYY = ys.reduce((acc, y) => acc + (y - yMean) ** 2, 0);
661	
662	            if (ssXX > 0) {
663	                slope = Number((ssXY / ssXX).toFixed(6));
664	                rSquared = ssYY > 0 ? Number(((ssXY ** 2) / (ssXX * ssYY)).toFixed(4)) : 1;
665	            }
666	        }
667	
668	        const direction: 'improving' | 'stable' | 'degrading' | 'unknown' =
669	            slope === null ? 'unknown'
670	                : slope > 0.002 ? 'improving'
671	                    : slope < -0.002 ? 'degrading'
672	                        : 'stable';
673	
674	        // ── 2. Explore / exploit ──────────────────────────────
675	        // Exploration = cross_event_status is 'pending_signal' or 'conflict' (engine pushed a test action).
676	        // Exploitation = confirmed, resolved, or 'none' (engine used its best known action).
677	        let exploreCount = 0;
678	        let exploitCount = 0;
679	        for (const r of rows) {
680	            const status = r.cross_event_status ?? 'none';
681	            if (status === 'pending_signal' || status === 'conflict') {
682	                exploreCount++;
683	            } else {
684	                exploitCount++;
685	            }
686	        }
687	        const total = rows.length;
688	        const exploreRatio = total > 0 ? Number((exploreCount / total).toFixed(4)) : null;
689	
690	        // ── 3. Trust blocks ───────────────────────────────────
691	        // A trust block is an outcome that was logged with failure_reason_code = 'TRUST_GATE'
692	        // OR execution_status = 'FAILED' while failure_reason_code contains 'TRUST'.
693	        const blockedCount = rows.filter((r) => {
694	            const code = (r.failure_reason_code ?? '').toUpperCase();
695	            return code.includes('TRUST') || code === 'TRUST_GATE';
696	        }).length;
697	
698	        return c.json({
699	            drift: {
700	                slope,
701	                confidence: rSquared,
702	                window_size: chronological.length,
703	                direction,
704	                points: points.slice(-30), // cap response size — last 30 points enough for a sparkline
705	            },
706	            explore_exploit: {
707	                explore_count: exploreCount,
708	                exploit_count: exploitCount,
709	                total,
710	                explore_ratio: exploreRatio,
711	            },
712	            trust_blocks: {
713	                blocked_count: blockedCount,
714	                total,
715	            },
716	            // All-time action aggregates from fact_outcomes — available even when trust gate blocks the engine.
717	            action_aggregates: actionAggregates,
718	        }, 200);
719	    } catch (err: any) {
720	        console.error('[task-analytics] unexpected error:', err.message);
721	        return c.json({ error: 'Internal server error', code: 'INTERNAL_ERROR', details: err.message }, 500);
722	    }
723	});
