843	        const confidenceSourceReason = result.confidence_source_reason ?? 'unknown_confidence_source_reason';
844	        const thresholdHint = scopeThresholdProgress
845	            ? scopeThresholdProgress.next_threshold === null
846	                ? `Evidence bucket: ${scopeThresholdProgress.bucket} (${scopeThresholdProgress.current_samples} samples, cohort-anchor reached).`
847	                : `Evidence bucket: ${scopeThresholdProgress.bucket} (${scopeThresholdProgress.current_samples} samples, ${scopeThresholdProgress.remaining_to_next_bucket} to ${scopeThresholdProgress.next_threshold}).`
848	            : null;
849	        const scopeLabel = servedScope === 'agent_scoped'
850	            ? 'Based on this agent\'s logged outcomes only'
851	            : fallbackApplied
852	                ? 'Agent-specific evidence is still warming. Temporarily using blended cohort outcomes for lower uncertainty.'
853	                : 'Based on all agents\' combined outcomes';
854	
855	        const output = buildActionableOutput(result);
856	        const lastSeenAt = output.data_window?.last_seen_at ?? null;
857	        const dataFreshness = buildRecommendationDataFreshness(
858	            result._data_source ?? 'unknown',
859	            lastSeenAt,
860	        );
861	
862	        let scopedEvidenceActions = result.all_actions;
863	        let scopedEvidenceSource: 'engine' | 'task_performance_mv' | 'task_performance_fact_fallback' = 'engine';
864	        let evidenceTaskName = taskName;
865	
866	        // Always fetch agent-scoped action evidence when an agent_id is provided.
867	        // The engine may have served customer_blended results (scope fallback) whose
868	        // all_actions contain cross-agent totals — those numbers must NOT appear in
869	        // the per-agent leaderboard. Force a per-agent evidence fetch in three cases:
870	        //   1. Trust gate blocked (engine returns [])
871	        //   2. Scope fell back to customer_blended (actions are cross-agent)
872	        //   3. Engine returned no actions at all
873	        if (scopedAgentId && (result._trust_gate_blocked || servedScope === 'customer_blended' || scopedEvidenceActions.length === 0)) {
874	            const taskCandidates = toUniqueTaskCandidates([
875	                taskName,
876	                requestedTaskName,
877	                normalizeTaskSlug(taskName),
878	                normalizeTaskSlug(requestedTaskName),
