885	            for (const candidateTask of taskCandidates) {
886	                const { rows, source } = await fetchTaskActionPerformance({
887	                    customerId,
888	                    taskName: candidateTask,
889	                    agentId: scopedAgentId,
890	                    windowStart,
891	                    contextFilter,
892	                });
893	
894	                if (!rows.length) {
895	                    continue;
896	                }
897	
898	                scopedEvidenceActions = rows.map((row) => ({
899	                    action_id: row.action_id,
900	                    action_name: row.action_name,
901	                    total_count: Number(row.total_count ?? 0),
902	                    effective_sample_count: Number(row.effective_sample_count ?? row.total_count ?? 0),
903	                    success_count: Number(row.success_count ?? 0),
904	                    success_rate: Number(row.success_rate ?? 0),
905	                    resolution_rate: Number(row.resolution_rate ?? row.success_rate ?? 0),
906	                    ml_score: row.ml_score === null || row.ml_score === undefined ? null : Number(row.ml_score),
907	                    semantic_cluster_convergence: Number(row.semantic_cluster_convergence ?? 0.5),
908	                    last_seen_at: row.last_seen_at ?? null,
909	                }));
910	
911	                evidenceTaskName = candidateTask;
912	                scopedEvidenceSource = source === 'mv'
913	                    ? 'task_performance_mv'
914	                    : 'task_performance_fact_fallback';
915	                break;
916	            }
917	        }
918	
919	        const scopedTaskOutcomeTotal = scopedEvidenceActions.reduce(
920	            (sum, action) => sum + Math.max(0, Number(action.total_count ?? 0)),
921	            0,
922	        );
923	
924	        const totalOutcomes = result.all_actions.reduce(
925	            (sum, action) => sum + Math.max(0, Number(action.total_count ?? 0)),
926	            0,
927	        );
928	        const medianSuccessRate = medianOf(
929	            result.all_actions.map((action) => Number(action.resolution_rate ?? Number.NaN)),
930	        );
931	        // Run cohort upsert, data sources, and LLM narrative in parallel.
932	        // LLM narrative is skipped when the agent is trust-blocked (no actions = no useful narrative).
933	        // Data sources uses a 2s timeout — those COUNT(*) queries on raw fact_outcomes
