971	        ]);
972	        const cohortReliability = computeCohortReliability(result, cohortCycle);
973	
974	        const traceability = buildTraceability({
975	            result,
976	            requestedScope,
977	            servedScope,
978	            fallbackApplied,
979	            scopeReason,
980	        });
981	
