983	        const narrativeOverride = narrative
984	            ? {
985	                message: narrative.message,
986	                reason: {
987	                    summary: narrative.summary,
988	                    evidence: narrative.evidence,
989	                    confidence_note: narrative.confidence_note,
990	                },
991	                llm_narrative: {
992	                    headline: narrative.headline,
993	                    narrative: narrative.narrative,
994	                    next_steps: narrative.next_steps,
995	                    risk_factors: narrative.risk_factors,
996	                    trend_direction: narrative.trend_direction,
997	                    generated: true,
998	                    model: process.env.RECOMMENDATION_NARRATIVE_MODEL ?? 'gpt-4o-mini',
999	                },
1000	            }
1001	            : {
1002	                llm_narrative: {
1003	                    headline: null,
1004	                    narrative: null,
1005	                    next_steps: null,
1006	                    risk_factors: null,
1007	                    trend_direction: null,
1008	                    generated: false,
1009	                    model: null,
1010	                },
1011	            };
1012	
1013	        // Build cohort history from active + previous cycle for timeline display
1014	        const cohortHistory = [
1015	            cohortCycle.active_cycle
1016	                ? {
1017	                    cycle_id: cohortCycle.active_cycle.cycle_id,
1018	                    opened_at: cohortCycle.active_cycle.opened_at,
1019	                    closed_at: cohortCycle.active_cycle.closed_at,
1020	                    close_reason: cohortCycle.active_cycle.close_reason,
1021	                    elapsed_days: cohortCycle.active_cycle.elapsed_days,
1022	                    outcomes_in_cycle: cohortCycle.active_cycle.outcomes_in_cycle,
1023	                    confidence_source: cohortCycle.active_cycle.opened_confidence_source,
1024	                    is_active: true,
1025	                }
1026	                : null,
1027	            cohortCycle.previous_cycle
1028	                ? {
1029	                    cycle_id: cohortCycle.previous_cycle.cycle_id,
1030	                    opened_at: cohortCycle.previous_cycle.opened_at,
1031	                    closed_at: cohortCycle.previous_cycle.closed_at,
1032	                    close_reason: cohortCycle.previous_cycle.close_reason,
1033	                    elapsed_days: cohortCycle.previous_cycle.elapsed_days,
1034	                    outcomes_in_cycle: cohortCycle.previous_cycle.outcomes_in_cycle,
1035	                    confidence_source: cohortCycle.previous_cycle.opened_confidence_source,
1036	                    is_active: false,
1037	                }
1038	                : null,
1039	        ].filter(Boolean);
1040	
1041	        return c.json(
1042	            {
1043	                ...output,
1044	                ...narrativeOverride,
1045	                agent_id: result.agent_id,
1046	                agent_scope: servedScope,
1047	                scope_label: scopeLabel,
1048	                scope_transition: {
