1050	                    served_scope: servedScope,
1051	                    fallback_applied: fallbackApplied,
1052	                    reason: scopeReason,
1053	                    threshold_hint: thresholdHint,
1054	                    threshold_bucket: scopeThresholdProgress?.bucket ?? null,
1055	                    current_samples: scopeThresholdProgress?.current_samples ?? null,
1056	                    next_threshold: scopeThresholdProgress?.next_threshold ?? null,
1057	                    remaining_samples_to_next_bucket:
1058	                        scopeThresholdProgress?.remaining_to_next_bucket ?? null,
1059	                    switch_back_rule: requestedScope === 'agent_scoped'
1060	                        ? `Switches back to agent-only automatically at >=${MIN_SAMPLES_STABLE} min samples and >=${Math.round(AGENT_SCOPE_MIN_CONFIDENCE * 100)}% confidence.`
1061	                        : null,
1062	                },
1063	                data_freshness: dataFreshness,
1064	                cohort_cycle: cohortCycle,
1065	                cohort_history: cohortHistory,
1066	                cohort_reliability: cohortReliability,
1067	                customer_id: customerId,
1068	                // Context filter applied to this recommendation — null when no context params provided
1069	                context_filter: contextFilter.resolved
