1072	                        label: contextFilter.label,
1073	                        issue_type: rawIssueType,
1074	                        environment: rawEnvironment,
1075	                        customer_tier: rawCustomerTier,
1076	                    }
1077	                    : {
1078	                        context_id: null,
1079	                        label: contextFilter.label,
1080	                        issue_type: rawIssueType,
1081	                        environment: rawEnvironment,
1082	                        customer_tier: rawCustomerTier,
1083	                    },
1084	                trust_blocked: isTrustBlocked,
1085	                trust_status: isTrustBlocked ? ((result as any)._trust_status ?? null) : null,
1086	                noise_gate: result._noise_gate ?? null,
1087	                simulation_guardrail: result._simulation_guardrail ?? null,
1088	                confidence_source: confidenceSource,
1089	                confidence_source_reason: confidenceSourceReason,
1090	                traceability,
1091	                policy_gate: {
1092	                    trust_blocked: !!result._trust_gate_blocked,
1093	                    trust_status: result._trust_status ?? null,
1094	                },
1095	                debug_scope: {
1096	                    requested_agent_id: scopedAgentId,
1097	                    requested_task_name: requestedTaskName,
1098	                    effective_task_name: taskName,
1099	                    evidence_task_name: evidenceTaskName,
1100	                    strict_agent_scope: strictAgentScope,
1101	                    evidence_source: scopedEvidenceSource,
1102	                    evidence_action_count: scopedEvidenceActions.length,
1103	                    trust_gate_blocked: !!result._trust_gate_blocked,
1104	                },
1105	                // ISSUE 1: Action registry validation.
1106	                // Tells the developer if the recommended action matches what they have registered.
1107	                // action_mismatch=true means the recommended action name does not exist in
1108	                // their dim_actions registry - they should check their action naming.
1109	                // warning is null when everything matches (do not show it in the dashboard).
1110	                action_registry: {
1111	                    registered_actions: result.registered_actions,
