1117	                        : null,
1118	                },
1119	                // Present only when agent_id is scoped. Shows the split between
1120	                // uploaded historical outcomes and live SDK outcomes for this agent+task,
1121	                // so the developer knows what fraction of confidence comes from each source.
1122	                data_sources: dataSources,
1123	                // Always return task-scoped evidence actions for display,
1124	                // including trust-gated responses where decision state may be blocked.
1125	                all_actions: scopedEvidenceActions.map((a) => ({
1126	                    action_id: a.action_id,
1127	                    action_name: a.action_name,
1128	                    total_count: a.total_count,
1129	                    effective_sample_count: a.effective_sample_count,
1130	                    success_count: a.success_count,
1131	                    success_rate: a.success_rate,
1132	                    resolution_rate: a.resolution_rate,
1133	                    ml_score: a.ml_score ?? null,
1134	                    semantic_cluster_convergence: a.semantic_cluster_convergence ?? null,
1135	                    last_seen_at: a.last_seen_at,
