1137	                // Authoritative task outcomes for gating/display on the dashboard.
1138	                task_total_outcomes: scopedTaskOutcomeTotal,
1139	            },
1140	            200
1141	        );
1142	    } catch (err: any) {
1143	        console.error('[get-recommendations] unexpected error:', err.message);
1144	        return c.json(
