    environment: this.config.environment,
};
```

And the `OutcomePayload` type:
```
export interface OutcomePayload {
  decision_id: string;
  agent_id: string;
  customer_id: string;
  task_type: string;
  action_name: string;
  upstream_name: string;
  original_action: string;
  executed_action: string;
  mode: string;
  rerouted: boolean;
  success?: boolean;
  latency_ms: number;
  timestamp: string;
  ingestion_source: 'mcp';
  environment: string;
}
```

The `logDecision` in gateway-proxy.ts does NOT include the `enrichmentScores` in the payload. That's intentional since the outcome payload doesn't have a field for it.

Actually wait, there's another concern. In `gateway-proxy.ts` line 311-326:
```
const payload: OutcomePayload = {
    decision_id: record.decisionId,
    agent_id: record.agentId,
    customer_id: record.customerId,
    task_type: record.taskType,
    action_name: record.actionName,
    upstream_name: record.upstreamName,
    original_action: record.originalAction,
    executed_action: record.executedAction,
    mode: record.mode,
    rerouted: record.rerouted,
    latency_ms: record.latencyMs,
    timestamp: new Date().toISOString(),
    ingestion_source: 'mcp',
    environment: this.config.environment,
};
```

The `mode` field in `OutcomePayload` is `string` but `record.mode` is `GatewayMode` which is `'bootstrap' | LIMode`. The 'bootstrap' value would be logged as a mode string. Is that valid? Looking at the API endpoint, it probably expects 'recommend', 'assist', or 'auto'. Logging 'bootstrap' could cause issues if the backend validates this field.

But wait, in bootstrap mode, outcomes wouldn't be logged at all, because `handleListTools` returns empty list in bootstrap mode and the auto-mode rerouting only happens in auto mode. But `handleCallTool` DOES log outcomes even in bootstrap mode if the tool is called from the enriched list. Actually, looking at handleCallTool:
```
const mode = this.modeManager.resolveMode(taskContext.taskType);
```

And at line 178:
```
if (mode === 'auto' && !this.config.shadowMode) {
```

Only auto mode does rerouting. But the outcome logging at lines 219-232 always happens if the tool call succeeds. So in bootstrap mode, `record.mode` would be `'bootstrap'`.

But can an agent even call a tool in bootstrap mode? If tools/list returns tools in bootstrap mode (line 115 of gateway-proxy.ts injects li_recommend only in non-bootstrap modes), and the agent calls a regular upstream tool, it'll be logged with mode='bootstrap'. This could be an issue if the backend validates the mode field.

Now, let me also think about the `score-fetcher.ts` file. It has `FETCH_TIMEOUT_MS = 500` (500ms). But in `fetchWithTimeout`, it uses BOTH an `AbortController` and `Promise.race`:
```
private async fetchWithTimeout(
    taskType: string,
    customerId: string,
    agentId: string,
  ): Promise<ScoredAction[]> {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), FETCH_TIMEOUT_MS);

    try {
      const promise = this.liApi.getScores(taskType, customerId, agentId);
      const result = await Promise.race([
        promise,
        new Promise<never>((_, reject) =>
          setTimeout(() => reject(new Error('Score fetch timed out')), FETCH_TIMEOUT_MS),
        ),
      ]);
      return result;
    } finally {
      clearTimeout(timeout);
      controller.abort(); // Clean up
    }
  }
```

The double timeout (AbortController + Promise.race) is redundant and could cause issues. If the AbortController fires first (cancelling the fetch), and then the Promise.race timeout fires, the error from the Promise.race would be caught by the caller. But the AbortController abort would cause the fetch to throw a DOMException, which would also be caught. So there's a race condition in error handling.

The `finally` block does `controller.abort()` which is fine - it's a no-op if already aborted.

But the `Promise.race` creates a promise that never resolves (it only rejects). So if `this.liApi.getScores()` succeeds first, everything is fine. If it fails, the AbortController abort might fire first or the Promise.race might fire first.

This is a code smell but not necessarily a runtime bug since both paths lead to proper error handling.

Actually wait - there's a subtle issue. The AbortController is passed nowhere! It's created at line 101, but it's never passed to the fetch call (`this.liApi.getScores`). The `this.liApi.getScores` method calls `this.get` which calls `this.requestWithRetry` which calls `this.request`, and in `this.request`, a NEW `AbortController` is created for each request. So the outer `controller.abort()` at line 115 in score-fetcher.ts doesn't actually abort the inner fetch!

This means the 500ms timeout is only effective via the `Promise.race` mechanism, which rejects the outer promise but doesn't actually cancel the underlying HTTP request. The fetch continues running in the background. So the AbortController in score-fetcher.ts is completely useless.

